 *       <ui-drawer-header>
 *         <ui-drawer-title>Title</ui-drawer-title>
 *         <ui-drawer-description>...</ui-drawer-description>
 *       </ui-drawer-header>
 *       ...
 *       <ui-drawer-footer>...</ui-drawer-footer>
 *     </ui-drawer-content>
 *   </ui-drawer>
