type DrawerDirection = 'bottom' | 'top' | 'left' | 'right';
const SPRING_EASE = 'cubic-bezier(0.32, 0.72, 0, 1)';

export class UiDrawer extends WebComponent {
  static properties = {
    open: { type: Boolean, reflect: true },
    direction: { type: String, reflect: true },
